import { test, expect } from 'bun:test';
import { XGnosisEdgeVM } from './x-gnosis-vm';
import { computeIgnorancePenalty } from './valentinian-sin';

test('Topological Compassion: initial State represents maximum resistance', () => {
  const vm = new XGnosisEdgeVM(54, 0);
  // At v=0, defenseWeight = 54 - Math.min(0, 54) + 1 = 55
  expect(vm.defenseWeight).toBe(55);
  expect(vm.isHalted).toBe(false);
});

test('Waveform Collapse: observation consumes exactly 1 unit of defense weight', () => {
  const vm = new XGnosisEdgeVM(54, 0);
  const initialWeight = vm.defenseWeight;

  // Simulate a lightweight FlowFrame
  vm.processFrame({
    streamId: 1,
    sequence: 1,
    flags: 0,
    payload: new Uint8Array(10), // Complexity of 10 crossings
  });

  expect(vm.v).toBe(1);
  expect(vm.defenseWeight).toBe(initialWeight - 1);
  expect(vm.isHalted).toBe(false);
});

test('Stress-Energy Collapse: prevents execution if graph is heavier than defense constraints', () => {
  const vm = new XGnosisEdgeVM(54, 0); // Max weight is 55.

  // Simulate an impossibly dense FlowFrame (e.g. 100 crossings when limit is 55)
  const excessivePayload = new Uint8Array(100);

  expect(() => {
    vm.processFrame({
      streamId: 1,
      sequence: 1,
      flags: 0,
      payload: excessivePayload,
    });
  }).toThrow(/Stress-Energy Collapse/);
});

test('Thermodynamic Halting: Event Horizon exhaustion structurally stops VM loops', () => {
  const vm = new XGnosisEdgeVM(2, 0); // Tiny sandbox budget R=2

  // Observation 1: v transitions from 0 -> 1
  vm.processFrame({
    streamId: 1,
    sequence: 1,
    flags: 0,
    payload: new Uint8Array(1),
  });
  expect(vm.v).toBe(1);
  expect(vm.isHalted).toBe(false);

  // Observation 2: v incurs the dynamic ignorance penalty, so it exceeds R.
  const expectedSecondIncrement =
    1 + computeIgnorancePenalty(vm.valentinianState);
  vm.processFrame({
    streamId: 1,
    sequence: 2,
    flags: 0,
    payload: new Uint8Array(1),
  });
  expect(vm.v).toBeCloseTo(1 + expectedSecondIncrement, 12);
  expect(vm.isHalted).toBe(true);
  expect(vm.defenseWeight).toBe(1); // Settles at the sliver state

  // Observation 3: VM refuses to process further frames.
  expect(() => {
    vm.processFrame({
      streamId: 1,
      sequence: 3,
      flags: 0,
      payload: new Uint8Array(1),
    });
  }).toThrow(/Thermodynamic Halting/);
});

test('Free Will Phase Shift: does not mutate R or v structurally', () => {
  const vm = new XGnosisEdgeVM(54, 0);
  vm.shiftPhase(27);
  expect(vm.v).toBe(0);
  expect(vm.R).toBe(54);
  expect(vm.defenseWeight).toBe(55);
});
